const WebSocket = require('ws');
const http = require('http');

// Game state
const gameState = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  nextUnitId: 1,
  nextBuildingId: 1,
  mapWidth: 1000,
  mapHeight: 1000
};

// Unit types and their properties
const UNIT_TYPES = {
  warrior: { hp: 100, attack: 15, defense: 5, speed: 3, range: 1, cost: { gold: 50 } },
  archer: { hp: 60, attack: 20, defense: 2, speed: 2, range: 8, cost: { gold: 70 } },
  cavalry: { hp: 120, attack: 18, defense: 8, speed: 6, range: 1, cost: { gold: 100 } },
  worker: { hp: 40, attack: 3, defense: 1, speed: 2, range: 1, cost: { gold: 20 } }
};

// Building types and their properties
const BUILDING_TYPES = {
  base: { hp: 500, cost: { gold: 0 }, buildTime: 0, providesSupply: 20 },
  barracks: { hp: 300, cost: { gold: 150 }, buildTime: 5000, trainsUnits: ['warrior', 'archer'] },
  stable: { hp: 300, cost: { gold: 200 }, buildTime: 7000, trainsUnits: ['cavalry'] },
  tower: { hp: 200, cost: { gold: 100 }, buildTime: 4000, attack: 25, range: 10 },
  farm: { hp: 100, cost: { gold: 60 }, buildTime: 3000, providesSupply: 10 },
  mine: { hp: 150, cost: { gold: 80 }, buildTime: 4000, goldPerTick: 5 }
};

const server = http.createServer((req, res) => {
  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end('RTS Game Server Running');
});

const wss = new WebSocket.Server({ server });

function generatePlayerId() {
  return 'player_' + Math.random().toString(36).substr(2, 9);
}

function distance(x1, y1, x2, y2) {
  return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

function createPlayer(ws) {
  const playerId = generatePlayerId();
  const spawnX = Math.random() * (gameState.mapWidth - 200) + 100;
  const spawnY = Math.random() * (gameState.mapHeight - 200) + 100;

  const player = {
    id: playerId,
    ws: ws,
    name: 'Player ' + playerId.substr(7),
    resources: { gold: 300 },
    supply: 0,
    maxSupply: 0,
    color: '#' + Math.floor(Math.random() * 16777215).toString(16).padStart(6, '0'),
    spawnX,
    spawnY,
    alive: true
  };

  gameState.players.set(playerId, player);

  // Create starting base
  const baseId = createBuilding(playerId, 'base', spawnX, spawnY);

  // Create starting workers
  for (let i = 0; i < 3; i++) {
    createUnit(playerId, 'worker', spawnX + (i - 1) * 20, spawnY + 40);
  }

  return player;
}

function createUnit(playerId, type, x, y) {
  const template = UNIT_TYPES[type];
  if (!template) return null;

  const player = gameState.players.get(playerId);
  if (!player) return null;

  if (player.supply + 1 > player.maxSupply) return null;

  const unitId = 'unit_' + gameState.nextUnitId++;
  const unit = {
    id: unitId,
    playerId,
    type,
    x: clamp(x, 0, gameState.mapWidth),
    y: clamp(y, 0, gameState.mapHeight),
    hp: template.hp,
    maxHp: template.hp,
    attack: template.attack,
    defense: template.defense,
    speed: template.speed,
    range: template.range,
    state: 'idle',
    targetX: null,
    targetY: null,
    attackTargetId: null,
    alive: true
  };

  gameState.units.set(unitId, unit);
  player.supply += 1;
  recalculateSupply(playerId);

  broadcastToAll({
    type: 'unit_created',
    unit: sanitizeUnit(unit)
  });

  return unitId;
}

function createBuilding(playerId, type, x, y) {
  const template = BUILDING_TYPES[type];
  if (!template) return null;

  const player = gameState.players.get(playerId);
  if (!player) return null;

  const buildingId = 'bldg_' + gameState.nextBuildingId++;
  const building = {
    id: buildingId,
    playerId,
    type,
    x: clamp(x, 0, gameState.mapWidth),
    y: clamp(y, 0, gameState.mapHeight),
    hp: template.hp,
    maxHp: template.hp,
    built: type === 'base',
    buildProgress: type === 'base' ? 100 : 0,
    buildTime: template.buildTime,
    buildStartTime: type === 'base' ? null : Date.now(),
    trainingQueue: [],
    alive: true
  };

  gameState.buildings.set(buildingId, building);
  recalculateSupply(playerId);

  broadcastToAll({
    type: 'building_created',
    building: sanitizeBuilding(building)
  });

  return buildingId;
}

function recalculateSupply(playerId) {
  const player = gameState.players.get(playerId);
  if (!player) return;

  let maxSupply = 0;
  let currentSupply = 0;

  for (const [, building] of gameState.buildings) {
    if (building.playerId === playerId && building.alive && building.built) {
      const template = BUILDING_TYPES[building.type];
      if (template.providesSupply) {
        maxSupply += template.providesSupply;
      }
    }
  }

  for (const [, unit] of gameState.units) {
    if (unit.playerId === playerId && unit.alive) {
      currentSupply += 1;
    }
  }

  player.maxSupply = maxSupply;
  player.supply = currentSupply;
}

function sanitizeUnit(unit) {
  return {
    id: unit.id,
    playerId: unit.playerId,
    type: unit.type,
    x: unit.x,
    y: unit.y,
    hp: unit.hp,
    maxHp: unit.maxHp,
    state: unit.state,
    alive: unit.alive
  };
}

function sanitizeBuilding(building) {
  return {
    id: building.id,
    playerId: building.playerId,
    type: building.type,
    x: building.x,
    y: building.y,
    hp: building.hp,
    maxHp: building.maxHp,
    built: building.built,
    buildProgress: building.buildProgress,
    alive: building.alive,
    trainingQueue: building.trainingQueue
  };
}

function sanitizePlayer(player) {
  return {
    id: player.id,
    name: player.name,
    resources: { ...player.resources },
    supply: player.supply,
    maxSupply: player.maxSupply,
    color: player.color,
    alive: player.alive
  };
}

function sendToPlayer(playerId, message) {
  const player = gameState.players.get(playerId);
  if (player && player.ws && player.ws.readyState === WebSocket.OPEN) {
    player.ws.send(JSON.stringify(message));
  }
}

function broadcastToAll(message) {
  const data = JSON.stringify(message);
  for (const [, player] of gameState.players) {
    if (player.ws && player.ws.readyState === WebSocket.OPEN) {
      player.ws.send(data);
    }
  }
}

function broadcastGameState() {
  const units = [];
  for (const [, unit] of gameState.units) {
    if (unit.alive) units.push(sanitizeUnit(unit));
  }

  const buildings = [];
  for (const [, building] of gameState.buildings) {
    if (building.alive) buildings.push(sanitizeBuilding(building));
  }

  const players = [];
  for (const [, player] of gameState.players) {
    players.push(sanitizePlayer(player));
  }

  broadcastToAll({
    type: 'game_state',
    units,
    buildings,
    players
  });
}

function handleCommand(playerId, command) {
  const player = gameState.players.get(playerId);
  if (!player || !player.alive) {
    sendToPlayer(playerId, { type: 'error', message: 'Player not active' });
    return;
  }

  switch (command.action) {
    case 'move':
      handleMove(playerId, command);
      break;
    case 'attack':
      handleAttack(playerId, command);
      break;
    case 'build':
      handleBuild(playerId, command);
      break;
    case 'train':
      handleTrain(playerId, command);
      break;
    case 'stop':
      handleStop(playerId, command);
      break;
    case 'gather':
      handleGather(playerId, command);
      break;
    case 'chat':
      handleChat(playerId, command);
      break;
    default:
      sendToPlayer(playerId, { type: 'error', message: 'Unknown command: ' + command.action });
  }
}

function handleMove(playerId, command) {
  const { unitIds, targetX, targetY } = command;

  if (!Array.isArray(unitIds) || unitIds.length === 0) {
    sendToPlayer(playerId, { type: 'error', message: 'No units specified' });
    return;
  }

  if (typeof targetX !== 'number' || typeof targetY !== 'number') {
    sendToPlayer(playerId, { type: 'error', message: 'Invalid target coordinates' });
    return;
  }

  const clampedX = clamp(targetX, 0, gameState.mapWidth);
  const clampedY = clamp(targetY, 0, gameState.mapHeight);

  const movedUnits = [];

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || !unit.alive) continue;

    unit.state = 'moving';
    unit.targetX = clampedX;
    unit.targetY = clampedY;
    unit.attackTargetId = null;
    movedUnits.push(unitId);
  }

  if (movedUnits.length > 0) {
    broadcastToAll({
      type: 'units_moving',
      playerId,
      unitIds: movedUnits,
      targetX: clampedX,
      targetY: clampedY
    });
  }
}

function handleAttack(playerId, command) {
  const { unitIds, targetId } = command;

  if (!Array.isArray(unitIds) || unitIds.length === 0) {
    sendToPlayer(playerId, { type: 'error', message: 'No units specified' });
    return;
  }

  // Target can be a unit or building
  const targetUnit = gameState.units.get(targetId);
  const targetBuilding = gameState.buildings.get(targetId);
  const target = targetUnit || targetBuilding;

  if (!target || !target.alive) {
    sendToPlayer(playerId, { type: 'error', message: 'Invalid target' });
    return;
  }

  if (target.playerId === playerId) {
    sendToPlayer(playerId, { type: 'error', message: 'Cannot attack own units/buildings' });
    return;
  }

  const attackingUnits = [];

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || !unit.alive) continue;

    unit.state = 'attacking';
    unit.attackTargetId = targetId;
    unit.targetX = target.x;
    unit.targetY = target.y;
    attackingUnits.push(unitId);
  }

  if (attackingUnits.length > 0) {
    broadcastToAll({
      type: 'units_attacking',
      playerId,
      unitIds: attackingUnits,
      targetId
    });
  }
}

function handleBuild(playerId, command) {
  const { buildingType, x, y } = command;

  const template = BUILDING_TYPES[buildingType];
  if (!template) {
    sendToPlayer(playerId, { type: 'error', message: 'Unknown building type: ' + buildingType });
    return;
  }

  if (buildingType === 'base') {
    sendToPlayer(playerId, { type: 'error', message: 'Cannot build additional bases' });
    return;
  }

  const player = gameState.players.get(playerId);

  if (player.resources.gold < template.cost.gold) {
    sendToPlayer(playerId, { type: 'error', message: 'Not enough gold. Need: ' + template.cost.gold + ', have: ' + player.resources.gold });
    return;
  }

  // Check for collision with existing buildings
  for (const [, building] of gameState.buildings) {
    if (building.alive && distance(x, y, building.x, building.y) < 40) {
      sendToPlayer(playerId, { type: 'error', message: 'Too close to another building' });
      return;
    }
  }

  player.resources.gold -= template.cost.gold;

  const buildingId = createBuilding(playerId, buildingType, x, y);

  if (buildingId) {
    sendToPlayer(playerId, {
      type: 'build_started',
      buildingId,
      buildingType,
      cost: template.cost
    });
  }
}

function handleTrain(playerId, command) {
  const { buildingId, unitType } = command;

  const building = gameState.buildings.get(buildingId);
  if (!building || building.playerId !== playerId || !building.alive || !building.built) {
    sendToPlayer(playerId, { type: 'error', message: 'Invalid or incomplete building' });
    return;
  }

  const buildingTemplate = BUILDING_TYPES[building.type];
  if (!buildingTemplate.trainsUnits || !buildingTemplate.trainsUnits.includes(unitType)) {
    sendToPlayer(playerId, { type: 'error', message: 'This building cannot train ' + unitType });
    return;
  }

  const unitTemplate = UNIT_TYPES[unitType];
  const player = gameState.players.get(playerId);

  if (player.resources.gold < unitTemplate.cost.gold) {
    sendToPlayer(playerId, { type: 'error', message: 'Not enough gold. Need: ' + unitTemplate.cost.gold });
    return;
  }

  if (building.trainingQueue.length >= 5) {
    sendToPlayer(playerId, { type: 'error', message: 'Training queue is full' });
    return;
  }

  player.resources.gold -= unitTemplate.cost.gold;

  const trainTime = 3000 + Math.floor(unitTemplate.cost.gold * 20);

  building.trainingQueue.push({
    unitType,
    startTime: building.trainingQueue.length === 0 ? Date.now() : null,
    trainTime,
    progress: 0
  });

  if (building.trainingQueue.length === 1) {
    building.trainingQueue[0].startTime = Date.now();
  }

  sendToPlayer(playerId, {
    type: 'training_queued',
    buildingId,
    unitType,
    queueLength: building.trainingQueue.length
  });

  broadcastToAll({
    type: 'building_updated',
    building: sanitizeBuilding(building)
  });
}

function handleStop(playerId, command) {
  const { unitIds } = command;

  if (!Array.isArray(unitIds)) return;

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || !unit.alive) continue;

    unit.state = 'idle';
    unit.targetX = null;
    unit.targetY = null;
    unit.attackTargetId = null;
  }

  broadcastToAll({
    type: 'units_stopped',
    playerId,
    unitIds
  });
}

function handleGather(playerId, command) {
  const { unitIds, targetBuildingId } = command;

  if (!Array.isArray(unitIds)) return;

  const targetBuilding = gameState.buildings.get(targetBuildingId);
  if (!targetBuilding || targetBuilding.playerId !== playerId || !targetBuilding.alive) {
    sendToPlayer(playerId, { type: 'error', message: 'Invalid building' });
    return;
  }

  if (targetBuilding.type !== 'mine') {
    sendToPlayer(playerId, { type: 'error', message: 'Can only gather at mines' });
    return;
  }

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || !unit.alive) continue;
    if (unit.type !== 'worker') continue;

    unit.state = 'gathering';
    unit.targetX = targetBuilding.x;
    unit.targetY = targetBuilding.y;
    unit.gatherTargetId = targetBuildingId;
    unit.attackTargetId = null;
  }
}

function handleChat(playerId, command) {
  const player = gameState.players.get(playerId);
  if (!player) return;

  const message = String(command.message || '').slice(0, 200);

  broadcastToAll({
    type: 'chat',
    playerId,
    playerName: player.name,
    message
  });
}

// Game loop - runs at ~20 ticks per second
const TICK_RATE = 50; // ms per tick
let lastTickTime = Date.now();

function gameTick() {
  const now = Date.now();
  const dt = (now - lastTickTime) / 1000; // delta time in seconds
  lastTickTime = now;

  // Update building construction
  for (const [, building] of gameState.buildings) {
    if (!building.alive || building.built) continue;

    const elapsed = now - building.buildStartTime;
    building.buildProgress = Math.min(100, (elapsed / building.buildTime) * 100);

    if (building.buildProgress >= 100) {
      building.built = true;
      building.buildProgress = 100;
      recalculateSupply(building.playerId);

      broadcastToAll({
        type: 'building_complete',
        buildingId: building.id,
        building: sanitizeBuilding(building)
      });
    }
  }

  // Update training queues
  for (const [, building] of gameState.buildings) {
    if (!building.alive || !building.built || building.trainingQueue.length === 0) continue;

    const currentTraining = building.trainingQueue[0];
    if (!currentTraining.startTime) {
      currentTraining.startTime = now;
    }

    const elapsed = now - currentTraining.startTime;
    currentTraining.progress = Math.min(100, (elapsed / currentTraining.trainTime) * 100);

    if (currentTraining.progress >= 100) {
      // Spawn the unit
      const spawnX = building.x + (Math.random() * 40 - 20);
      const spawnY = building.y + 40;

      const unitId = createUnit(building.playerId, currentTraining.unitType, spawnX, spawnY);

      if (unitId) {
        broadcastToAll({
          type: 'training_complete',
          buildingId: building.id,
          unitType: currentTraining.unitType,
          unitId
        });
      }

      building.trainingQueue.shift();

      // Start next in queue
      if (building.trainingQueue.length > 0) {
        building.trainingQueue[0].startTime = now;
      }
    }
  }

  // Update resource generation from mines
  for (const [, building] of gameState.buildings) {
    if (!building.alive || !building.built || building.type !== 'mine') continue;

    const template = BUILDING_TYPES[building.type];
    const player = gameState.players.get(building.playerId);
    if (player) {
      // Check if workers are nearby gathering
      let workerCount = 0;
      for (const [, unit] of gameState.units) {
        if (unit.alive && unit.playerId === building.playerId &&
            unit.state === 'gathering' && unit.gatherTargetId === building.id &&
            distance(unit.x, unit.y, building.x, building.y) < 30) {
          workerCount++;
        }
      }
      if (workerCount > 0) {
        player.resources.gold += template.goldPerTick * Math.min(workerCount, 3) * dt;
        player.resources.gold = Math.floor(player.resources.gold);
      }
    }
  }

  // Update unit movement and combat
  for (const [, unit] of gameState.units) {
    if (!unit.alive) continue;

    if (unit.state === 'moving' || unit.state === 'gathering') {
      if (unit.targetX !== null && unit.targetY !== null) {
        const dx = unit.targetX - unit.x;
        const dy = unit.targetY - unit.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        const stopDistance = unit.state === 'gathering' ? 25 : 5;

        if (dist > stopDistance) {
          const moveAmount = unit.speed * dt * 30;
          const ratio = Math.min(moveAmount / dist, 1);
          unit.x += dx * ratio;
          unit.y += dy * ratio;
          unit.x = clamp(unit.x, 0, gameState.mapWidth);
          unit.y = clamp(unit.y, 0, gameState.mapHeight);
        } else {
          if (unit.state === 'moving') {
            unit.state = 'idle';
            unit.targetX = null;
            unit.targetY = null;
          }
          // gathering units stay in gathering state
        }
      }
    }

    if (unit.state === 'attacking') {
      const target = gameState.units.get(unit.attackTargetId) || gameState.buildings.get(unit.attackTargetId);

      if (!target || !target.alive) {
        unit.state = 'idle';
        unit.attackTargetId = null;
        unit.targetX = null;
        unit.targetY = null;
        continue;
      }

      const dist = distance(unit.x, unit.y, target.x, target.y);
      const attackRange = unit.range * 20;

      if (dist > attackRange) {
        // Move towards target
        const dx = target.x - unit.x;
        const dy = target.y - unit.y;
        const moveAmount = unit.speed * dt * 30;
        const ratio = Math.min(moveAmount / dist, 1);
        unit.x += dx * ratio;
        unit.y += dy * ratio;
        unit.x = clamp(unit.x, 0, gameState.mapWidth);
        unit.y = clamp(unit.y, 0, gameState.mapHeight);
      } else {
        // Attack
        if (!unit.lastAttackTime || now - unit.lastAttackTime > 1000) {
          const targetDef = target.defense || 0;
          const damage = Math.max(1, unit.attack - targetDef);
          target.hp -= damage;
          unit.lastAttackTime = now;

          broadcastToAll({
            type: 'combat',
            attackerId: unit.id,
            targetId: target.id,
            damage,
            targetHp: target.hp,
            targetMaxHp: target.maxHp
          });

          if (target.hp <= 0) {
            target.alive = false;
            target.hp = 0;

            broadcastToAll({
              type: 'entity_destroyed',
              entityId: target.id,
              entityType: gameState.units.has(target.id) ? 'unit' : 'building',
              killedBy: unit.playerId
            });

            recalculateSupply(target.playerId);

            // Award gold for kills
            const killer = gameState.players.get(unit.playerId);
            if (killer) {
              killer.resources.gold += 25;
            }

            unit.state = 'idle';
            unit.attackTargetId = null;

            // Check if player lost all buildings
            checkPlayerElimination(target.playerId);
          }
        }
      }
    }
  }

  // Tower attacks - buildings with attack capability
  for (const [, building] of gameState.buildings) {
    if (!building.alive || !building.built) continue;

    const template = BUILDING_TYPES[building.type];
    if (!template.attack) continue;

    if (!building.lastAttackTime || now - building.lastAttackTime > 1500) {
      // Find nearest enemy unit in range
      let nearestEnemy = null;
      let nearestDist = Infinity;

      for (const [, unit] of gameState.units) {
        if (!unit.alive || unit.playerId === building.playerId) continue;
        const dist = distance(building.x, building.y, unit.x, unit.y);
        if (dist < template.range * 20 && dist < nearestDist) {
          nearestDist = dist;
          nearestEnemy = unit;
        }
      }

      if (nearestEnemy) {
        const damage = Math.max(1, template.attack - nearestEnemy.defense);
        nearestEnemy.hp -= damage;
        building.lastAttackTime = now;

        broadcastToAll({
          type: 'combat',
          attackerId: building.id,
          targetId: nearestEnemy.id,
          damage,
          targetHp: nearestEnemy.hp,
          targetMaxHp: nearestEnemy.maxHp
        });

        if (nearestEnemy.hp <= 0) {
          nearestEnemy.alive = false;
          nearestEnemy.hp = 0;

          broadcastToAll({
            type: 'entity_destroyed',
            entityId: nearestEnemy.id,
            entityType: 'unit',
            killedBy: building.playerId
          });

          recalculateSupply(nearestEnemy.playerId);
        }
      }
    }
  }

  // Clean up dead entities periodically
  for (const [id, unit] of gameState.units) {
    if (!unit.alive && (now - (unit.deathTime || now)) > 5000) {
      if (!unit.deathTime) unit.deathTime = now;
      else gameState.units.delete(id);
    }
  }

  for (const [id, building] of gameState.buildings) {
    if (!building.alive && (now - (building.deathTime || now)) > 5000) {
      if (!building.deathTime) building.deathTime = now;
      else gameState.buildings.delete(id);
    }
  }
}

function checkPlayerElimination(playerId) {
  const player = gameState.players.get(playerId);
  if (!player || !player.alive) return;

  let hasBuildings = false;
  for (const [, building] of gameState.buildings) {
    if (building.playerId === playerId && building.alive) {
      hasBuildings = true;
      break;
    }
  }

  if (!hasBuildings) {
    let hasUnits = false;
    for (const [, unit] of gameState.units) {
      if (unit.playerId === playerId && unit.alive) {
        hasUnits = true;
        break;
      }
    }

    if (!hasUnits) {
      player.alive = false;

      broadcastToAll({
        type: 'player_eliminated',
        playerId,
        playerName: player.name
      });

      // Check for winner
      const alivePlayers = [];
      for (const [, p] of gameState.players) {
        if (p.alive) alivePlayers.push(p);
      }

      if (alivePlayers.length === 1 && gameState.players.size > 1) {
        broadcastToAll({
          type: 'game_over',
          winnerId: alivePlayers[0].id,
          winnerName: alivePlayers[0].name
        });
      }
    }
  }
}

// Passive gold income for all players
let lastIncomeTime = Date.now();
function passiveIncome() {
  const now = Date.now();
  if (now - lastIncomeTime >= 5000) {
    for (const [, player] of gameState.players) {
      if (player.alive) {
        player.resources.gold += 10;
      }
    }
    lastIncomeTime = now;
  }
}

// WebSocket connection handler
wss.on('connection', (ws) => {
  console.log('New connection');

  let player = null;

  ws.on('message', (data) => {
    let message;
    try {
      message = JSON.parse(data);
    } catch (e) {
      ws.send(JSON.stringify({ type: 'error', message: 'Invalid JSON' }));
      return;
    }

    if (message.type === 'join') {
      if (player) {
        ws.send(JSON.stringify({ type: 'error', message: 'Already joined' }));
        return;
      }

      player = createPlayer(ws);

      if (message.name && typeof message.name === 'string') {
        player.name = message.name.slice(0, 20);
      }

      console.log(`Player ${player.name} (${player.id}) joined`);

      // Send welcome message with full game state
      const units = [];
      for (const [, unit] of gameState.units) {
        if (unit.alive) units.push(sanitizeUnit(unit));
      }

      const buildings = [];
      for (const [, building] of gameState.buildings) {
        if (building.alive) buildings.push(sanitizeBuilding(building));
      }

      const players = [];
      for (const [, p] of gameState.players) {
        players.push(sanitizePlayer(p));
      }

      ws.send(JSON.stringify({
        type: 'welcome',
        playerId: player.id,
        player: sanitizePlayer(player),
        mapWidth: gameState.mapWidth,
        mapHeight: gameState.mapHeight,
        units,
        buildings,
        players,
        unitTypes: UNIT_TYPES,
        buildingTypes: BUILDING_TYPES
      }));

      // Notify others
      broadcastToAll({
        type: 'player_joined',
        player: sanitizePlayer(player)
      });

      return;
    }

    if (!player) {
      ws.send(JSON.stringify({ type: 'error', message: 'Must join first. Send { type: "join", name: "YourName" }' }));
      return;
    }

    if (message.type === 'command') {
      handleCommand(player.id, message);
      return;
    }

    if (message.type === 'ping') {
      ws.send(JSON.stringify({ type: 'pong', serverTime: Date.now() }));
      return;
    }
  });

  ws.on('close', () => {
    if (player) {
      console.log(`Player ${player.name} (${player.id}) disconnected`);

      player.alive = false;

      // Remove all player units and buildings
      for (const [, unit] of gameState.units) {
        if (unit.playerId === player.id) {
          unit.alive = false;
        }
      }

      for (const [, building] of gameState.buildings) {
        if (building.playerId === player.id) {
          building.alive = false;
        }
      }

      broadcastToAll({
        type: 'player_left',
        playerId: player.id,
        playerName: player.name
      });

      gameState.players.delete(player.id);
    }
  });

  ws.on('error', (err) => {
    console.error('WebSocket error:', err.message);
  });
});

// Game loop interval
setInterval(() => {
  gameTick();
  passiveIncome();
}, TICK_RATE);

// Broadcast full state periodically for sync
setInterval(() => {
  broadcastGameState();
}, 2000);

// Send individual player resource updates more frequently
setInterval(() => {
  for (const [playerId, player] of gameState.players) {
    if (player.ws && player.ws.readyState === WebSocket.OPEN) {
      sendToPlayer(playerId, {
        type: 'resources_update',
        resources: { ...player.resources },
        supply: player.supply,
        maxSupply: player.maxSupply
      });
    }
  }
}, 500);

